select ca_county,d_qoy, d_year,sum(ss_ext_sales_price) as store_sales  from store_sales,date_dim,customer_address, item  where ss_sold_date_sk = d_date_sk   and ss_addr_sk=ca_address_sk   and ss_item_sk = i_item_sk   and i_color IN ('purple', 'sandy')   and i_manager_id BETWEEN 36 and 55   and ss_list_price between 77 and 91   and ca_state in ('GA','IL')  group by ca_county,d_qoy, d_year),  ws AS ( /*+ HashJoin(web_sales item) NoNestLoop(web_sales item) */
